(()=>{'use strict';
const $=s=>document.querySelector(s);
const LS='doit-table-detail-visible-v1';
let storeOverlay,storeBody;
function T(v){return String(v??'').trim()}
function css(){if($('#mobileTableUi280Css'))return;const st=document.createElement('style');st.id='mobileTableUi280Css';st.textContent=`
.tableTools280{display:flex;flex-wrap:wrap;gap:8px;align-items:center;justify-content:space-between;padding:10px 12px;border-bottom:1px solid #e5e7eb;background:#fff}
.receiverPick280{display:flex;align-items:center;gap:8px;flex:1;min-width:260px}
.receiverPick280 b{white-space:nowrap;color:#087b34;font-size:13px}
.storePickBtn280{min-width:0;flex:1;height:38px;border:1px solid #16a34a;border-radius:9px;background:#f0fdf4;color:#065f46;font-weight:950;padding:0 9px;text-align:left;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.detailToggle280{height:38px;border:1px solid #94a3b8;background:#f8fafc;color:#334155;border-radius:9px;font-weight:950;padding:0 10px;white-space:nowrap}
.field.singleHidden280{position:absolute!important;left:-9999px!important;width:1px!important;height:1px!important;overflow:hidden!important;opacity:0!important;pointer-events:none!important}
.storeOverlay280{position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:172;display:none;align-items:center;justify-content:center;padding:18px}.storeOverlay280.on{display:flex}.storeSheet280{width:min(92vw,760px);max-height:86vh;background:#fff;border-radius:18px;box-shadow:0 22px 80px #0006;display:flex;flex-direction:column;overflow:hidden}.storeHead280{background:#087b34;color:#fff;padding:14px 16px;display:flex;justify-content:space-between;align-items:center;gap:8px;font-size:17px}.storeClose280{height:34px;border:1px solid #ffffff66;background:#0001;color:#fff;border-radius:8px;font-weight:900;padding:0 12px}.storeSearch280{padding:12px;border-bottom:1px solid #e5e7eb}.storeSearch280 input{width:100%;height:44px;border:1px solid #cbd5e1;border-radius:10px;padding:0 12px;font-weight:900;font-size:15px}.storeBody280{padding:12px;overflow:auto}.storeGrid280{display:grid;grid-template-columns:repeat(2,1fr);gap:9px}.storeItem280{border:1px solid #d1d5db;background:#fff;border-radius:10px;padding:12px 10px;font-weight:950;text-align:left;font-size:14px;display:flex;gap:8px;align-items:center}.storeItem280 i{width:20px;height:20px;border:1px solid #9ca3af;border-radius:5px;display:inline-grid;place-items:center;font-style:normal;flex:0 0 auto}.storeItem280.on{border-color:#087b34;background:#ecfdf5;color:#065f27}.storeItem280.on i{background:#087b34;color:#fff;border-color:#087b34}.storeFoot280{padding:12px;border-top:1px solid #e5e7eb;display:grid;grid-template-columns:1fr 1fr;gap:10px}.storeFoot280 button{height:46px;border-radius:10px;font-weight:950;font-size:15px}.storeClear280{border:1px solid #d1d5db;background:#fff;color:#4b5563}.storeOk280{border:0;background:#087b34;color:#fff}
body.doitCompactPick .tbl th:nth-child(1),body.doitCompactPick .tbl td:nth-child(1),
body.doitCompactPick .tbl th:nth-child(2),body.doitCompactPick .tbl td:nth-child(2),
body.doitCompactPick .tbl th:nth-child(3),body.doitCompactPick .tbl td:nth-child(3){display:none!important}
body.doitCompactPick .tbl{min-width:720px!important;font-size:14px}
body.doitCompactPick .tbl th,body.doitCompactPick .tbl td{padding:10px 8px}
body.doitCompactPick .tbl td:nth-child(4),body.doitCompactPick .tbl th:nth-child(4){min-width:230px}
body.doitCompactPick .tbl input.pick{width:92px;height:38px;font-size:15px}
@media(max-width:720px){.tableTools280{position:sticky;top:56px;z-index:18}.receiverPick280{min-width:100%}.detailToggle280{width:100%}body.doitCompactPick .tbl{min-width:650px!important;font-size:15px}body.doitCompactPick .p b{font-size:15px}.tbl input.pick{font-size:16px}.storeOverlay280{padding:10px}.storeSheet280{width:96vw;max-height:88vh}.storeGrid280{grid-template-columns:1fr}.storeHead280{font-size:16px}}
`;document.head.appendChild(st)}
function detailVisible(){return localStorage.getItem(LS)==='1'}
function applyMode(){const show=detailVisible();document.body.classList.toggle('doitCompactPick',!show);const b=$('#detailToggle280');if(b)b.textContent=show?'ซ่อนรายละเอียด':'แสดงรายละเอียด'}
function hideDuplicateControls(){const store=$('#storeSelect'),start=$('#startDate'),end=$('#endDate');const storeField=store?.closest('.field');const dateField=start?.closest('.field')||end?.closest('.field');if(storeField)storeField.classList.add('singleHidden280');if(dateField)dateField.classList.add('singleHidden280')}
function storeOptions(){const main=$('#storeSelect');if(!main)return[];return[...main.options].map(o=>({value:o.value,text:T(o.textContent||o.value)})).filter(x=>x.value||x.text)}
function currentStore(){const main=$('#storeSelect');return main?main.value:''}
function setMainStore(v){const main=$('#storeSelect');if(!main)return;main.value=v;main.dispatchEvent(new Event('change',{bubbles:true}));main.dispatchEvent(new Event('input',{bubbles:true}));syncStoreButton();renderStorePicker()}
function syncStoreButton(){const b=$('#inlineStoreBtn280'),main=$('#storeSelect');if(!b||!main)return;const opt=[...main.options].find(o=>o.value===main.value);const txt=T(opt?.textContent||main.value);b.textContent=txt?`ส่งให้ร้าน: ${txt} ▼`:'ส่งให้ร้าน: เลือกร้านจริง ▼'}
function ensureStoreOverlay(){css();if(storeOverlay)return;storeOverlay=document.createElement('div');storeOverlay.className='storeOverlay280';storeOverlay.innerHTML='<div class="storeSheet280"><div class="storeHead280"><b>เลือกร้านจริงที่จะส่ง</b><button class="storeClose280">ปิด</button></div><div class="storeSearch280"><input id="storeSearch280" placeholder="ค้นหาร้าน"></div><div class="storeBody280"></div><div class="storeFoot280"><button class="storeClear280">ล้าง</button><button class="storeOk280">ตกลง</button></div></div>';document.body.appendChild(storeOverlay);storeBody=storeOverlay.querySelector('.storeBody280');storeOverlay.querySelector('.storeClose280').onclick=closeStorePicker;storeOverlay.querySelector('.storeOk280').onclick=closeStorePicker;storeOverlay.querySelector('.storeClear280').onclick=()=>setMainStore('');storeOverlay.onclick=e=>{if(e.target===storeOverlay)closeStorePicker()};storeOverlay.querySelector('#storeSearch280').oninput=renderStorePicker}
function renderStorePicker(){ensureStoreOverlay();const q=T($('#storeSearch280')?.value).toLowerCase(),cur=currentStore();let list=storeOptions();if(q)list=list.filter(x=>x.text.toLowerCase().includes(q)||x.value.toLowerCase().includes(q));storeBody.innerHTML='<div class="storeGrid280">'+list.map(x=>`<button class="storeItem280 ${x.value===cur?'on':''}" data-v="${String(x.value).replace(/"/g,'&quot;')}"><i>${x.value===cur?'✓':''}</i><span>${x.text}</span></button>`).join('')+'</div>';storeBody.querySelectorAll('.storeItem280').forEach(b=>b.onclick=()=>{const v=b.dataset.v;if(v===currentStore())setMainStore('');else setMainStore(v);closeStorePicker()})}
function openStorePicker(){ensureStoreOverlay();const s=$('#storeSearch280');if(s)s.value='';renderStorePicker();storeOverlay.classList.add('on')}
function closeStorePicker(){storeOverlay?.classList.remove('on')}
function install(){css();hideDuplicateControls();const tableTop=document.querySelector('.tableTop');if(tableTop&&!$('#tableTools280')){const bar=document.createElement('div');bar.id='tableTools280';bar.className='tableTools280';bar.innerHTML='<div class="receiverPick280"><b>ส่งให้ร้าน:</b><button id="inlineStoreBtn280" class="storePickBtn280" type="button">ส่งให้ร้าน: เลือกร้านจริง ▼</button></div><button id="detailToggle280" class="detailToggle280" type="button">แสดงรายละเอียด</button>';tableTop.insertAdjacentElement('afterend',bar);$('#inlineStoreBtn280').onclick=openStorePicker;$('#detailToggle280').onclick=()=>{localStorage.setItem(LS,detailVisible()?'0':'1');applyMode()}}
 const main=$('#storeSelect');if(main&&!main.dataset.inline280){main.dataset.inline280='1';main.addEventListener('change',syncStoreButton);main.addEventListener('input',syncStoreButton)}
 syncStoreButton();applyMode()}
function boot(){install();let n=0;const tick=()=>{install();const done=$('#inlineStoreBtn280')&&storeOptions().length>1;if(++n<40&&!done)setTimeout(tick,400)};setTimeout(tick,400)}
document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();
})();